//vip.opstream17.com/20240401/3659_1b927432/index.m3u8"}]}],"time":"45 phút/tập","description":"Tại thành Hoà Dương nhuốm đầy tội ác, Phan Việt - mỹ nam được vô số thiếu nữ yêu mến, kết hôn cùng người mà ai nấy đều ghét bỏ, Dương Thái Vi. Vào ngày đại hôn, Dương Thái Vi bị giết hại, nghi phạm lại chính là Phan Việt. Sau khi \"từ cõi chết trở về\", Dương Thái Vi trở lại đầy mạnh mẽ dưới vỏ bọc \"ác nữ\" Thượng Quan Chỉ, quyết tâm vạch trần bộ mặt thật của Phan Việt. Trong quá trình chiến đấu chống lại thế lực tà ác \"tứ đại gia tộc\" và điều tra các vụ án cũ, hai trái tim sát lại gần nhau. Dương Thái Vi phát hiện thủ phạm thực sự giết hại mình là một người khác, còn Phan Việt từ đầu đến cuối vẫn luôn yêu cô sâu đậm. Khi mọi chuyện sắp viên mãn, kẻ đứng sau một lần nữa lại giăng bẫy, đẩy hai người vào tình cảnh vạn kiếp bất phục.","tmdb":{"type":"tv","id":"235619","season":1,"vote_average":6.875,"vote_count":8},"modified":"2024-04-01T21:55:17.000Z"},{"id":"64efe167ee400b53d2dc50c7","_id":"64efe167ee400b53d2dc50c7","title":"Cuộc Chiến Sinh Tồn - 7 Escape","origin_name":"The Escape of the Seven: War for Survival","slug":"7-escape","year":2023,"type":"series","genre":[{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a2300e0fc277084dfd6d2","name":"Hàn Quốc","slug":"han-quoc"}],"lang_key":"Vietsub","episode_current":"Hoàn Tất (17/17)","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":true,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"1","slug":"1","filename":"The Escape of the Seven Tap 1","link_embed":"https://vip.opstream13.com/share/1579779b98ce9edb98dd85606f2c119d","link_m3u8":"https://vip.opstream13.com/20230916/1046_05d18add/index.m3u8"},{"name":"2","slug":"2","filename":"The Escape of the Seven - EP02","link_embed":"https://vip.opstream13.com/share/299a23a2291e2126b91d54f3601ec162","link_m3u8":"https://vip.opstream13.com/